class Solution:
    def predictPartyVictory(self, senate):
        alive = list(senate)
        active = list(range(len(senate)))
        while True:
            r = sum(1 for i in active if alive[i] == 'R')
            d = sum(1 for i in active if alive[i] == 'D')
            if d == 0:
                return 'Radiant'
            if r == 0:
                return 'Dire'
            order = list(active)
            m = len(order)
            for pos in range(m):
                i = order[pos]
                if alive[i] == 'X':
                    continue
                for step in range(1, m):
                    j = order[(pos + step) % m]
                    if alive[j] != 'X' and alive[j] != alive[i]:
                        alive[j] = 'X'
                        break
            active = [i for i in active if alive[i] != 'X']

