var predictPartyVictory = function(senate) {
    const n = senate.length;
    const radiant = [];
    const dire = [];
    for (let i = 0; i < n; i++) {
        if (senate[i] === 'R') radiant.push(i); else dire.push(i);
    }
    let ri = 0, di = 0;
    while (ri < radiant.length && di < dire.length) {
        const r = radiant[ri++];
        const d = dire[di++];
        if (r < d) radiant.push(r + n); else dire.push(d + n);
    }
    return ri < radiant.length ? 'Radiant' : 'Dire';
};
